import{_ as t,o as s,c as n,a2 as a}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Context Management","description":"","frontmatter":{"title":"Context Management","status":"complete"},"headers":[],"relativePath":"research/concepts/context-management/index.md","filePath":"research/concepts/context-management/index.md"}'),o={name:"research/concepts/context-management/index.md"};function r(l,e,i,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="context-management" tabindex="-1">Context Management <a class="header-anchor" href="#context-management" aria-label="Permalink to &quot;Context Management&quot;">​</a></h1><blockquote><p>Synthesized from studying 17 coding agents: OpenHands, Codex, Gemini CLI, OpenCode, Goose, Claude Code, Aider, ForgeCode, mini-SWE-agent, Warp, Ante, Droid, Junie CLI, Pi Coding Agent, Sage Agent, TongAgents, and Capy.</p></blockquote><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Context management is the central design challenge of coding agents. Nearly every architectural decision — sub-agents, compaction, memory files, skill systems — exists to address it.</p><h3 id="the-fundamental-mismatch" tabindex="-1">The Fundamental Mismatch <a class="header-anchor" href="#the-fundamental-mismatch" aria-label="Permalink to &quot;The Fundamental Mismatch&quot;">​</a></h3><p>Real codebases are vast. A medium-sized project might contain 500K–5M tokens of source code, plus documentation, configuration, test suites, and build artifacts. Meanwhile, LLM context windows range from 32K to 1M tokens. Even at the frontier, a single model call cannot &quot;see&quot; an entire non-trivial codebase. The agent must decide what to include, what to summarize, and what to discard — and it must decide correctly, because including the wrong context is worse than including none at all.</p><p>ForgeCode makes this explicit: <strong>&quot;Context size is a multiplier on the right entry point, not a substitute for it.&quot;</strong> A model with 200K context starting in the right file outperforms a model with 1M context starting in the wrong directory.</p><h3 id="quality-degradation-under-context-pressure" tabindex="-1">Quality Degradation Under Context Pressure <a class="header-anchor" href="#quality-degradation-under-context-pressure" aria-label="Permalink to &quot;Quality Degradation Under Context Pressure&quot;">​</a></h3><p>From Anthropic&#39;s Claude Code documentation: <em>&quot;Most best practices are based on one constraint: Claude&#39;s context window fills up fast, and performance degrades as it fills.&quot;</em> This is unusually transparent about the fundamental limitation. As context fills, models start &quot;forgetting&quot; earlier instructions, make more errors, and lose coherence. The degradation is not linear — performance drops sharply once a model-specific threshold is exceeded.</p><h3 id="the-compounding-problem-in-agentic-loops" tabindex="-1">The Compounding Problem in Agentic Loops <a class="header-anchor" href="#the-compounding-problem-in-agentic-loops" aria-label="Permalink to &quot;The Compounding Problem in Agentic Loops&quot;">​</a></h3><p>Single-loop agents face compounding context pressure across turns:</p><ol><li><strong>Exploration bloat</strong>: Finding the right file requires reading directory listings, search results, and candidate files. Most of this is irrelevant but persists in context.</li><li><strong>History accumulation</strong>: Each tool call and result stays in the conversation. By message 20, the context window is dominated by stale exploration results.</li><li><strong>Cost amplification</strong>: Every token in context is re-sent on every turn. A 100K-token context over 30 turns means 3M input tokens billed — at $3/M tokens, that&#39;s $9 in input costs alone for a single task.</li></ol><h3 id="the-design-space" tabindex="-1">The Design Space <a class="header-anchor" href="#the-design-space" aria-label="Permalink to &quot;The Design Space&quot;">​</a></h3><p>Agents have converged on three fundamental strategies, used alone or in combination:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Philosophy</th><th>Example Agents</th></tr></thead><tbody><tr><td><strong>Reduce what goes in</strong></td><td>Selective context loading, entry-point discovery</td><td>Aider, ForgeCode, Gemini CLI</td></tr><tr><td><strong>Compress what&#39;s there</strong></td><td>Summarization, truncation, sliding windows</td><td>OpenHands, Codex, Goose, OpenCode</td></tr><tr><td><strong>Partition across windows</strong></td><td>Sub-agents with bounded context</td><td>Claude Code, ForgeCode, Ante, Capy</td></tr></tbody></table><p>The choice between these strategies reveals a deeper tension: <strong>information fidelity vs. token efficiency</strong>. Every compression loses something. Every partition creates a communication boundary. The art of context management is choosing what to lose.</p><hr><h2 id="token-counting" tabindex="-1">Token Counting <a class="header-anchor" href="#token-counting" aria-label="Permalink to &quot;Token Counting&quot;">​</a></h2><p>Before you can manage context, you must measure it. Agents take surprisingly different approaches to this seemingly straightforward problem.</p><h3 id="approach-1-exact-tokenizer-counting" tabindex="-1">Approach 1: Exact Tokenizer Counting <a class="header-anchor" href="#approach-1-exact-tokenizer-counting" aria-label="Permalink to &quot;Approach 1: Exact Tokenizer Counting&quot;">​</a></h3><p>The gold standard. Use the model&#39;s actual tokenizer (e.g., tiktoken for OpenAI models) to count tokens precisely. Aider uses this for short texts, falling back to sampling for longer content:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Aider&#39;s hybrid approach</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> token_count</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> text</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &lt;</span><span style="color:#FAB387;"> 200</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">main_model</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">token_count</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # Exact</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Sample every 100th line, extrapolate</span></span>
<span class="line"><span style="color:#CDD6F4;">    lines </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> text</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">splitlines</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">keepends</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    step </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lines</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> //</span><span style="color:#FAB387;"> 100</span><span style="color:#CBA6F7;"> or</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"><span style="color:#CDD6F4;">    sample </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> lines</span><span style="color:#9399B2;">[::</span><span style="color:#EBA0AC;font-style:italic;">step</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> sample_tokens </span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;&quot;</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">join</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">sample</span><span style="color:#9399B2;">))</span><span style="color:#94E2D5;"> *</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Trade-off</strong>: Accurate but requires loading a tokenizer model (startup cost, dependency) and is slow for large texts. The sampling fallback is a pragmatic compromise.</p><h3 id="approach-2-byte-based-heuristic-estimation" tabindex="-1">Approach 2: Byte-Based Heuristic Estimation <a class="header-anchor" href="#approach-2-byte-based-heuristic-estimation" aria-label="Permalink to &quot;Approach 2: Byte-Based Heuristic Estimation&quot;">​</a></h3><p>Codex CLI&#39;s most distinctive design decision — no tokenizer at all:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">const</span><span style="color:#FAB387;"> APPROX_BYTES_PER_TOKEN</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 4</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> approx_token_count</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">text</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> /</span><span style="color:#FAB387;"> APPROX_BYTES_PER_TOKEN</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This works because English text averages roughly 4 bytes per token across modern tokenizers. The estimation is combined with server-reported token counts from the most recent API response — the heuristic only covers tokens added <em>since</em> the last API call.</p><p><strong>Trade-off</strong>: Fast and dependency-free, but less accurate for non-English text, code with unusual symbol density, or heavily structured output. Acceptable because the estimation only needs to be &quot;close enough&quot; for compaction threshold decisions, not exact.</p><h3 id="approach-3-server-reported-only" tabindex="-1">Approach 3: Server-Reported Only <a class="header-anchor" href="#approach-3-server-reported-only" aria-label="Permalink to &quot;Approach 3: Server-Reported Only&quot;">​</a></h3><p>OpenCode takes the simplest approach: no client-side token counting at all. It relies entirely on the provider&#39;s reported <code>TokenUsage</code> after each response:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> TokenUsage</span><span style="color:#CBA6F7;"> struct</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    InputTokens         </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    OutputTokens        </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    CacheCreationTokens </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    CacheReadTokens     </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Trade-off</strong>: Zero client complexity, but context overflow is only detected <em>after</em> it happens (the provider returns an error). This requires reactive error handling rather than proactive budget management.</p><h3 id="approach-4-pre-computed-token-budgets" tabindex="-1">Approach 4: Pre-Computed Token Budgets <a class="header-anchor" href="#approach-4-pre-computed-token-budgets" aria-label="Permalink to &quot;Approach 4: Pre-Computed Token Budgets&quot;">​</a></h3><p>Several agents allocate fixed budgets to context components upfront:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Budget Allocation Example</th></tr></thead><tbody><tr><td><strong>Aider</strong></td><td>Repo-map: 1K default (expandable to 8K); response reserve: 4K minimum</td></tr><tr><td><strong>Junie CLI</strong></td><td>~2K system, ~20K active files, ~10K related files, ~2K build/test</td></tr><tr><td><strong>Warp</strong></td><td>Explicit allocation across system prompt, codebase, history, user message, tool defs, response reserve</td></tr></tbody></table><p>This approach treats context like a financial budget — each category gets an allocation, and components compete for the remainder.</p><h3 id="cost-tracking" tabindex="-1">Cost Tracking <a class="header-anchor" href="#cost-tracking" aria-label="Permalink to &quot;Cost Tracking&quot;">​</a></h3><p>Token counting increasingly happens alongside cost tracking. OpenCode computes per-turn costs using model pricing data:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">cost </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MInCached</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CacheCreationTokens</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> +</span></span>
<span class="line"><span style="color:#CDD6F4;">    model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MOutCached</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CacheReadTokens</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> +</span></span>
<span class="line"><span style="color:#CDD6F4;">    model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MIn</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">InputTokens</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> +</span></span>
<span class="line"><span style="color:#CDD6F4;">    model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MOut</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">OutputTokens</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>Claude Code&#39;s <code>/context</code> command surfaces what&#39;s consuming space. Codex tracks cumulative token usage across the session. This visibility helps both the agent and the user make informed decisions about when to compact or reset.</p><h3 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Agents</th><th>Accuracy</th><th>Speed</th><th>Dependencies</th></tr></thead><tbody><tr><td>Exact tokenizer</td><td>Aider (short text)</td><td>High</td><td>Slow</td><td>Tokenizer library</td></tr><tr><td>Sampling + extrapolation</td><td>Aider (long text)</td><td>Medium-High</td><td>Fast</td><td>Tokenizer library</td></tr><tr><td>Byte heuristic (~4 B/tok)</td><td>Codex</td><td>Medium</td><td>Fastest</td><td>None</td></tr><tr><td>Server-reported only</td><td>OpenCode</td><td>Exact (post-hoc)</td><td>N/A</td><td>None</td></tr><tr><td>Pre-computed budgets</td><td>Aider, Junie, Warp</td><td>Varies</td><td>Fast</td><td>Optional</td></tr></tbody></table><p>The trend is clear: <strong>accuracy matters less than you&#39;d think</strong>. Compaction thresholds are set conservatively (80-95% of window), so a ±10% estimation error rarely causes problems. Speed and simplicity win.</p><hr><h2 id="compaction" tabindex="-1">Compaction <a class="header-anchor" href="#compaction" aria-label="Permalink to &quot;Compaction&quot;">​</a></h2><p>Compaction is the richest area of divergence across agents. When context grows too large, something must give. The strategies range from brute-force truncation to sophisticated LLM-powered summarization pipelines.</p><h3 id="summarization" tabindex="-1">Summarization <a class="header-anchor" href="#summarization" aria-label="Permalink to &quot;Summarization&quot;">​</a></h3><p>The most common approach: ask an LLM to summarize older conversation history, replacing verbose history with a compact summary.</p><p><strong>OpenCode</strong> uses a focused summarization prompt that preserves what matters for continuation:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>&quot;Provide a detailed but concise summary of our conversation above.</span></span>
<span class="line"><span> Focus on: what was done, what we&#39;re doing, which files we&#39;re working on,</span></span>
<span class="line"><span> and what we&#39;re going to do next.&quot;</span></span></code></pre></div><p>The summary message replaces all prior history — subsequent turns start from the summary rather than the full history.</p><p><strong>Claude Code</strong> offers both auto-compaction and manual <code>/compact</code> with focus instructions:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>/compact Focus on the API changes    # Directed compaction</span></span>
<span class="line"><span>/compact Keep the test results       # Selective preservation</span></span></code></pre></div><p>Claude Code also re-reads CLAUDE.md from disk after compaction, ensuring project instructions are never lost — a key design decision that other agents don&#39;t replicate.</p><p><strong>OpenHands</strong> implements two LLM-based condensers:</p><ul><li><strong>LLMSummarizingCondenser</strong>: Free-form summary of forgotten events</li><li><strong>StructuredSummaryCondenser</strong>: Categorized sections (&quot;Key Findings&quot;, &quot;Files Modified&quot;, &quot;Current Approach&quot;, &quot;Open Issues&quot;) — giving the agent a more organized view than free-form text</li></ul><p><strong>Droid</strong> claims the most ambitious approach: incremental compression with anchor points, where key decisions are preserved at full fidelity while surrounding context is compressed progressively. Each context piece carries a &quot;confidence&quot; score determining compression aggressiveness. This reportedly enables multi-week continuous sessions.</p><h3 id="truncation" tabindex="-1">Truncation <a class="header-anchor" href="#truncation" aria-label="Permalink to &quot;Truncation&quot;">​</a></h3><p>Rather than summarizing, simply cap or trim content. This is faster and cheaper than LLM-based summarization.</p><p><strong>Per-item truncation</strong> (Codex): Each tool output is capped at ~10KB, preserving the beginning (67%) and end (33%) with a middle elision marker. The asymmetric split keeps error messages (typically at the end) visible:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> prefix_size </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> limit </span><span style="color:#94E2D5;">*</span><span style="color:#FAB387;"> 2</span><span style="color:#94E2D5;"> /</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">   // ~67% from start</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> suffix_size </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> limit </span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">        // ~33% from end</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">prefix</span><span style="color:#9399B2;">}</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">…</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">truncated_chars</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;"> chars truncated…</span><span style="color:#F5C2E7;">\\n</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">suffix</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Observation-level truncation</strong> (mini-SWE-agent): If command output exceeds 10,000 characters, show head (5K) + tail (5K) with a warning. This is transparent to the model and encourages it to use more targeted commands.</p><p><strong>Search result limits</strong> (ForgeCode): <code>FORGE_MAX_SEARCH_RESULT_BYTES</code> (default 10KB) prevents a single grep from flooding context with thousands of matches.</p><p><strong>Global tool output pass</strong> (Codex): When total context is too large, a global pass truncates <em>all</em> function outputs with the configured policy — a blunt but effective last resort.</p><h3 id="sliding-window" tabindex="-1">Sliding Window <a class="header-anchor" href="#sliding-window" aria-label="Permalink to &quot;Sliding Window&quot;">​</a></h3><p>Drop older messages entirely, keeping only recent history.</p><p><strong>OpenHands&#39; ConversationWindowCondenser</strong> preserves initial context (setup/instructions) and recent events, forgetting everything in between:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> ConversationWindowCondenser</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">RollingCondenser</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    max_events</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 100</span></span>
<span class="line"><span style="color:#CDD6F4;">    keep_first</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 5</span><span style="color:#6C7086;font-style:italic;">   # Preserve initial setup/instructions</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Keep first K events + last (max - K) events; forget the middle</span></span></code></pre></div><p><strong>RecentEventsCondenser</strong> is even simpler: keep the last N events (default 50), discard everything else.</p><p><strong>AmortizedForgettingCondenser</strong> takes a gentler approach: gradual forgetting that preserves progressively more recent events, avoiding the harsh cliff of a fixed window.</p><p>The key insight across all sliding-window approaches: <strong>initial context matters</strong>. The system prompt, first user message, and setup instructions should be preserved even as the middle of the conversation is discarded.</p><h3 id="condenser-chains-openhands" tabindex="-1">Condenser Chains (OpenHands) <a class="header-anchor" href="#condenser-chains-openhands" aria-label="Permalink to &quot;Condenser Chains (OpenHands)&quot;">​</a></h3><p>OpenHands&#39; most powerful contribution is the <strong>PipelineCondenser</strong> — chaining multiple condensers in sequence:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">condenser</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">type </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;pipeline&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[[</span><span style="color:#CDD6F4;">condenser.stages</span><span style="color:#9399B2;">]]</span></span>
<span class="line"><span style="color:#CDD6F4;">type </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;observation_masking&quot;</span><span style="color:#6C7086;font-style:italic;">     # First: hide verbose observation content</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[[</span><span style="color:#CDD6F4;">condenser.stages</span><span style="color:#9399B2;">]]</span></span>
<span class="line"><span style="color:#CDD6F4;">type </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;conversation_window&quot;</span><span style="color:#6C7086;font-style:italic;">     # Then: apply sliding window</span></span>
<span class="line"><span style="color:#CDD6F4;">max_events </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 100</span></span>
<span class="line"><span style="color:#CDD6F4;">keep_first </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 5</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[[</span><span style="color:#CDD6F4;">condenser.stages</span><span style="color:#9399B2;">]]</span></span>
<span class="line"><span style="color:#CDD6F4;">type </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;llm_summarizing&quot;</span><span style="color:#6C7086;font-style:italic;">         # Finally: summarize if still too large</span></span>
<span class="line"><span style="color:#CDD6F4;">max_events </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 50</span></span></code></pre></div><p>This enables strategies like: &quot;First mask observation content, then apply a sliding window, then summarize if still too large.&quot; Each stage operates on the output of the previous, and any stage can short-circuit by returning a <code>CondensationAction</code> that requires controller intervention before proceeding.</p><p>OpenHands provides 10 condenser implementations that can be composed:</p><table tabindex="0"><thead><tr><th>Condenser</th><th>Strategy</th><th>LLM Cost</th></tr></thead><tbody><tr><td>NoOp</td><td>Pass-through</td><td>None</td></tr><tr><td>RecentEvents</td><td>Keep last N</td><td>None</td></tr><tr><td>ConversationWindow</td><td>First K + last N</td><td>None</td></tr><tr><td>AmortizedForgetting</td><td>Gradual progressive</td><td>None</td></tr><tr><td>ObservationMasking</td><td>Replace content with placeholders</td><td>None</td></tr><tr><td>BrowserOutput</td><td>Browser-specific masking</td><td>None</td></tr><tr><td>LLMAttention</td><td>LLM selects events to keep</td><td>1 call</td></tr><tr><td>LLMSummarizing</td><td>LLM summarizes forgotten events</td><td>1 call</td></tr><tr><td>StructuredSummary</td><td>Categorized section summary</td><td>1 call</td></tr><tr><td>Pipeline</td><td>Chain multiple condensers</td><td>Varies</td></tr></tbody></table><p>The agent can even request condensation itself via the <code>CondensationRequestTool</code> — a form of <strong>self-directed memory management</strong> where the agent decides when to forget.</p><h3 id="tool-pair-summarization-goose" tabindex="-1">Tool-Pair Summarization (Goose) <a class="header-anchor" href="#tool-pair-summarization-goose" aria-label="Permalink to &quot;Tool-Pair Summarization (Goose)&quot;">​</a></h3><p>Goose&#39;s most distinctive innovation: <strong>background summarization of tool_call + tool_result pairs</strong>. Each turn, a background task identifies old tool pairs and generates concise summaries:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Mark old messages invisible (kept for UI/persistence)</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">idx</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> _</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> in</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">summaries </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">    conversation</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">*</span><span style="color:#CDD6F4;">idx</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">set_agent_visible</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;">false</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Insert summaries in their place</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> summary</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> in</span><span style="color:#CDD6F4;"> summaries </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">    conversation</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">summary</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The originals are preserved for UI display and session persistence but marked <code>agent_visible: false</code> so the LLM never sees them. This is elegant — the complete history exists for debugging, but the LLM&#39;s view is progressively compressed.</p><p>Goose operates at three levels:</p><ol><li><strong>Proactive</strong> (pre-loop): Compact at 80% of context limit</li><li><strong>Reactive</strong> (error recovery): Compact on <code>ContextLengthExceeded</code>, max 2 attempts</li><li><strong>Background</strong> (per-turn): Asynchronous tool-pair summarization</li></ol><h3 id="moim-—-model-oriented-information-management-goose" tabindex="-1">MOIM — Model-Oriented Information Management (Goose) <a class="header-anchor" href="#moim-—-model-oriented-information-management-goose" aria-label="Permalink to &quot;MOIM — Model-Oriented Information Management (Goose)&quot;">​</a></h3><p>Each turn, before calling the LLM, Goose injects dynamic context from extensions via <code>inject_moim()</code>. Extensions provide per-turn context that&#39;s relevant <em>right now</em> — similar to RAG but driven by the extension ecosystem rather than vector search. The &quot;Top of Mind&quot; extension uses this to inject persistent user instructions.</p><h3 id="bounded-context-across-sub-agents" tabindex="-1">Bounded Context Across Sub-Agents <a class="header-anchor" href="#bounded-context-across-sub-agents" aria-label="Permalink to &quot;Bounded Context Across Sub-Agents&quot;">​</a></h3><p>Rather than compressing one window, partition the work across multiple windows.</p><p><strong>Claude Code</strong> makes this philosophy explicit: <em>&quot;Sub-agents are the most powerful context management tool.&quot;</em> Exploration happens in a separate context window; only the summary returns to the main conversation:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Main Context Window                    Sub-Agent Context Window</span></span>
<span class="line"><span>┌──────────────────────┐              ┌──────────────────────┐</span></span>
<span class="line"><span>│ Your conversation    │              │ Exploration task     │</span></span>
<span class="line"><span>│ (preserved)          │   ──spawn──▶ │ Reads 20 files       │</span></span>
<span class="line"><span>│                      │              │ Searches codebase    │</span></span>
<span class="line"><span>│                      │   ◀─summary─ │ Analyzes patterns    │</span></span>
<span class="line"><span>│ + compact summary    │              │ (all discarded)      │</span></span>
<span class="line"><span>└──────────────────────┘              └──────────────────────┘</span></span></code></pre></div><p><strong>ForgeCode</strong> takes this further with a three-agent pipeline (Sage → Muse → Forge) where each agent receives only distilled output from the previous stage — not raw exploration context.</p><p><strong>Ante</strong> distributes context across a meta-agent and sub-agents, with effective total context equal to the sum of all agent windows. <strong>Capy</strong> uses a spec document as the compression boundary: Captain distills exploration into a structured spec; Build receives only the spec plus codebase access.</p><h3 id="repo-map-structural-context-without-full-files-aider" tabindex="-1">Repo-Map: Structural Context Without Full Files (Aider) <a class="header-anchor" href="#repo-map-structural-context-without-full-files-aider" aria-label="Permalink to &quot;Repo-Map: Structural Context Without Full Files (Aider)&quot;">​</a></h3><p>Aider&#39;s repo-map is the most sophisticated approach to <em>preventing</em> context bloat rather than compressing it after the fact. The pipeline:</p><ol><li><strong>Tree-sitter parsing</strong>: Extract definitions and references from every source file (100+ languages)</li><li><strong>Dependency graph</strong>: Build file-level reference graph (A references symbols defined in B)</li><li><strong>Personalized PageRank</strong>: Rank files by importance, biased toward files currently in the chat and mentioned identifiers</li><li><strong>Token-budgeted selection</strong>: Include highest-ranked symbols until the budget (default 1024 tokens, expandable to 8K) is consumed</li></ol><p>The result is a compact structural map showing class definitions, function signatures, and import relationships — without function bodies, comments, or implementation details. The map dynamically resizes: expanding when no files are added (maximum codebase awareness), shrinking when files are present (leaving room for full content).</p><h3 id="semantic-entry-point-discovery-forgecode" tabindex="-1">Semantic Entry-Point Discovery (ForgeCode) <a class="header-anchor" href="#semantic-entry-point-discovery-forgecode" aria-label="Permalink to &quot;Semantic Entry-Point Discovery (ForgeCode)&quot;">​</a></h3><p>ForgeCode&#39;s context engine performs a semantic pass before any agent starts exploring:</p><ol><li>Index the project into vector embeddings</li><li>Analyze the task description semantically</li><li>Return ranked entry-point files and functions</li><li>Agent starts in the right place, using context to reason deeply rather than explore broadly</li></ol><p>ForgeCode claims &quot;up to 93% fewer tokens&quot; compared to naive exploration.</p><h3 id="no-compaction-mini-swe-agent" tabindex="-1">No Compaction (mini-SWE-agent) <a class="header-anchor" href="#no-compaction-mini-swe-agent" aria-label="Permalink to &quot;No Compaction (mini-SWE-agent)&quot;">​</a></h3><p>The deliberate anti-pattern: append everything, truncate nothing, summarize nothing.</p><p>This works because: (1) modern context windows are enormous (128K-200K+), (2) typical SWE-bench trajectories generate only 30K-60K tokens, (3) linear history means zero information loss, (4) trajectories are directly usable as fine-tuning data with no distribution shift.</p><p>mini-SWE-agent&#39;s position: <strong>&quot;Start with linear history, and only add compaction if you empirically need it.&quot;</strong> For benchmark-focused agents, this is surprisingly effective.</p><h3 id="compaction-strategy-comparison" tabindex="-1">Compaction Strategy Comparison <a class="header-anchor" href="#compaction-strategy-comparison" aria-label="Permalink to &quot;Compaction Strategy Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Strategy</th><th>Information Loss</th><th>LLM Cost</th><th>Latency</th><th>Best For</th></tr></thead><tbody><tr><td><strong>LLM summarization</strong></td><td>Medium (summary quality varies)</td><td>1 LLM call per compaction</td><td>High</td><td>Long multi-topic sessions</td></tr><tr><td><strong>Structured summary</strong></td><td>Low-Medium (categorized)</td><td>1 LLM call</td><td>High</td><td>Complex multi-step tasks</td></tr><tr><td><strong>Per-item truncation</strong></td><td>Low (head+tail preserved)</td><td>None</td><td>Negligible</td><td>Large tool outputs</td></tr><tr><td><strong>Sliding window</strong></td><td>High (old context lost)</td><td>None</td><td>Negligible</td><td>Simple short-lived sessions</td></tr><tr><td><strong>Condenser chains</strong></td><td>Configurable</td><td>Varies</td><td>Varies</td><td>Sophisticated long-running agents</td></tr><tr><td><strong>Tool-pair summarization</strong></td><td>Medium</td><td>1 call per pair</td><td>Background</td><td>Tool-heavy workflows</td></tr><tr><td><strong>Sub-agent partitioning</strong></td><td>Low (only summaries cross)</td><td>Extra agent calls</td><td>Medium</td><td>Exploration-heavy tasks</td></tr><tr><td><strong>Repo-map</strong></td><td>None (proactive selection)</td><td>None</td><td>Build cost</td><td>Codebase-aware editing</td></tr><tr><td><strong>Semantic entry-point</strong></td><td>None (proactive selection)</td><td>Embedding cost</td><td>Index cost</td><td>Large unfamiliar codebases</td></tr><tr><td><strong>No compaction</strong></td><td>None</td><td>None</td><td>None</td><td>Short tasks, fine-tuning data</td></tr></tbody></table><h3 id="compaction-triggers" tabindex="-1">Compaction Triggers <a class="header-anchor" href="#compaction-triggers" aria-label="Permalink to &quot;Compaction Triggers&quot;">​</a></h3><p>When does compaction fire? The thresholds reveal different risk tolerances:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Trigger</th><th>Philosophy</th></tr></thead><tbody><tr><td><strong>Goose</strong></td><td>80% of context window</td><td>Conservative — large buffer for response + tools</td></tr><tr><td><strong>Codex</strong></td><td>90% of context window</td><td>Moderate — smaller buffer</td></tr><tr><td><strong>OpenCode</strong></td><td>95% of context window</td><td>Aggressive — maximize history retention</td></tr><tr><td><strong>OpenHands</strong></td><td>Configurable event count (default 100)</td><td>Event-based, not token-based</td></tr><tr><td><strong>Claude Code</strong></td><td>Auto (configurable) + manual <code>/compact</code></td><td>Dual: system + user control</td></tr><tr><td><strong>Warp</strong></td><td><code>/fork-and-compact</code></td><td>User-initiated with conversation forking</td></tr></tbody></table><hr><h2 id="session-persistence" tabindex="-1">Session Persistence <a class="header-anchor" href="#session-persistence" aria-label="Permalink to &quot;Session Persistence&quot;">​</a></h2><p>Context management doesn&#39;t end when the session closes. How agents persist and restore conversation state determines whether work survives across sessions.</p><h3 id="sqlite-opencode" tabindex="-1">SQLite (OpenCode) <a class="header-anchor" href="#sqlite-opencode" aria-label="Permalink to &quot;SQLite (OpenCode)&quot;">​</a></h3><p>OpenCode stores all conversations in a SQLite database within the project directory:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> sessions</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    title </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#A6E3A1;"> &#39;&#39;</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    message_count </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    prompt_tokens </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    completion_tokens </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    summary_message_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    cost </span><span style="color:#CBA6F7;">REAL</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">),</span></span>
<span class="line"><span style="color:#CDD6F4;">    updated_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> messages</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    session_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> REFERENCES</span><span style="color:#CBA6F7;"> sessions</span><span style="color:#CDD6F4;">(id),</span></span>
<span class="line"><span style="color:#CBA6F7;">    role</span><span style="color:#CBA6F7;"> TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    parts </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,  </span><span style="color:#6C7086;font-style:italic;">-- JSON-serialized ContentPart array</span></span>
<span class="line"><span style="color:#CDD6F4;">    model </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span></code></pre></div><p>Benefits: ACID transactions, efficient queries over history, structured metadata (cost, token counts), foreign key relationships between sessions and messages. The <code>summary_message_id</code> field links to the compaction boundary — messages before the summary are excluded from future prompts.</p><h3 id="file-based-session-dumps" tabindex="-1">File-Based Session Dumps <a class="header-anchor" href="#file-based-session-dumps" aria-label="Permalink to &quot;File-Based Session Dumps&quot;">​</a></h3><p><strong>OpenHands</strong> uses an append-only EventStream backed by a FileStore, with events serialized as JSON and paginated for efficient retrieval. The immutable history means context management decisions are reversible — you can reconstruct what the agent saw at any point.</p><p><strong>Gemini CLI</strong> uses shadow git repositories for checkpointing:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>~/.gemini/history/&lt;project_hash&gt;/</span></span>
<span class="line"><span>├── .git/                    # Shadow git repository</span></span>
<span class="line"><span>├── conversation.json        # Full conversation history</span></span>
<span class="line"><span>├── tool_calls.json          # All tool calls and results</span></span>
<span class="line"><span>├── metadata.json            # Session metadata</span></span>
<span class="line"><span>└── files/                   # Snapshots of modified files</span></span></code></pre></div><p>Each turn auto-commits to the shadow repo, enabling git-based inspection of checkpoint history and restore via <code>/restore</code>.</p><p><strong>Pi Coding Agent</strong> uses JSONL with <code>id</code>/<code>parentId</code> fields forming a tree structure — supporting in-place branching, <code>/tree</code> navigation, and <code>/fork</code> without ever deleting history.</p><h3 id="memory-files-claude-md-gemini-md-opencode-md" tabindex="-1">Memory Files (CLAUDE.md, GEMINI.md, OpenCode.md) <a class="header-anchor" href="#memory-files-claude-md-gemini-md-opencode-md" aria-label="Permalink to &quot;Memory Files (CLAUDE.md, GEMINI.md, OpenCode.md)&quot;">​</a></h3><p>Persistent project-level instruction files that are loaded into context at session start:</p><table tabindex="0"><thead><tr><th>Agent</th><th>File</th><th>Hierarchy</th><th>JIT Discovery</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>CLAUDE.md</td><td>User → parent dirs → project → child dirs</td><td>Yes (on file access)</td></tr><tr><td><strong>Gemini CLI</strong></td><td>GEMINI.md</td><td>Global → workspace → JIT</td><td>Yes (on file access)</td></tr><tr><td><strong>OpenCode</strong></td><td>OpenCode.md</td><td>Project-level only</td><td>No</td></tr><tr><td><strong>Goose</strong></td><td>.goosehints + AGENTS.md</td><td>Global → project → directory</td><td>No</td></tr><tr><td><strong>Warp</strong></td><td>AGENTS.md</td><td>Global → project → directory</td><td>No</td></tr><tr><td><strong>Claude Code</strong></td><td>Auto-memory (MEMORY.md)</td><td>Per-project, machine-local</td><td>Loaded at start (first 200 lines)</td></tr></tbody></table><p>Claude Code&#39;s auto-memory is distinctive: the agent writes its own notes (<code>~/.claude/projects/&lt;project&gt;/memory/MEMORY.md</code>) that persist across sessions. Only the first 200 lines load at startup — a practical token budget threshold.</p><p>CLAUDE.md and GEMINI.md both support modular imports via <code>@path/to/file</code> syntax, and both survive compaction — they&#39;re re-read from disk after context is compressed.</p><h3 id="conversation-checkpointing-and-resume" tabindex="-1">Conversation Checkpointing and Resume <a class="header-anchor" href="#conversation-checkpointing-and-resume" aria-label="Permalink to &quot;Conversation Checkpointing and Resume&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Mechanism</th><th>Resume Command</th></tr></thead><tbody><tr><td><strong>Gemini CLI</strong></td><td>Shadow git repo checkpoints</td><td><code>/restore</code></td></tr><tr><td><strong>Claude Code</strong></td><td>Session naming + persistence</td><td><code>--resume</code>, <code>--name</code></td></tr><tr><td><strong>Pi Coding Agent</strong></td><td>JSONL tree-structured history</td><td><code>/tree</code>, <code>/fork</code></td></tr><tr><td><strong>Warp</strong></td><td>Warp Drive (cross-device, team-shared)</td><td>Conversation forking</td></tr><tr><td><strong>Droid</strong></td><td>Cross-interface persistence</td><td>Survives web ↔ CLI ↔ GitHub ↔ Slack transitions</td></tr></tbody></table><h3 id="the-persistence-context-tension" tabindex="-1">The Persistence-Context Tension <a class="header-anchor" href="#the-persistence-context-tension" aria-label="Permalink to &quot;The Persistence-Context Tension&quot;">​</a></h3><p>A subtle design tension: persistence and compaction are at odds. Compaction discards information to free context space, but persistence wants to retain everything for future sessions. Agents resolve this differently:</p><ul><li><strong>Goose</strong> keeps original messages with <code>agent_visible: false</code> — invisible to the LLM but preserved for persistence and UI</li><li><strong>OpenHands</strong> maintains the immutable EventStream separately from the condensed View — the full history is always available even as the agent&#39;s working view is compressed</li><li><strong>Codex</strong> preserves <code>GhostSnapshot</code> items through compaction — enabling undo/redo across compaction boundaries</li><li><strong>mini-SWE-agent</strong> sidesteps the tension entirely: no compaction means the saved trajectory exactly matches what the LLM saw, making it directly usable as training data</li></ul><hr><h2 id="tools-projects" tabindex="-1">Tools &amp; Projects <a class="header-anchor" href="#tools-projects" aria-label="Permalink to &quot;Tools &amp; Projects&quot;">​</a></h2><p>The ecosystem of tools for context management in coding agents spans five layers — from low-level token counting to high-level memory systems. This section catalogs the key open-source projects and services at each layer.</p><h3 id="tokenization-counting" tabindex="-1">Tokenization &amp; Counting <a class="header-anchor" href="#tokenization-counting" aria-label="Permalink to &quot;Tokenization &amp; Counting&quot;">​</a></h3><p>Accurate token counting is the foundation: every budget decision, compaction trigger, and cost estimate depends on it.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Language</th><th>Key Strength</th><th>License</th></tr></thead><tbody><tr><td><strong><a href="https://github.com/openai/tiktoken" target="_blank" rel="noreferrer">tiktoken</a></strong></td><td>Python (Rust core)</td><td>Exact counts for OpenAI models (GPT-4o, o1, o3); 3-6× faster than alternatives</td><td>MIT</td></tr><tr><td><strong><a href="https://github.com/huggingface/tokenizers" target="_blank" rel="noreferrer">tokenizers</a></strong></td><td>Rust (Python/JS/Ruby bindings)</td><td>Multi-model support (BPE, WordPiece, Unigram); alignment tracking maps tokens back to source spans</td><td>Apache 2.0</td></tr><tr><td><strong><a href="https://github.com/niieani/gpt-tokenizer" target="_blank" rel="noreferrer">gpt-tokenizer</a></strong></td><td>TypeScript</td><td>Browser-ready; built-in <code>isWithinTokenLimit()</code> for early-exit checks and <code>estimateCost()</code></td><td>MIT</td></tr><tr><td><strong><a href="https://github.com/belladoreai/llama-tokenizer-js" target="_blank" rel="noreferrer">llama-tokenizer-js</a></strong></td><td>JavaScript</td><td>Client-side LLaMA tokenization (~1 ms); critical since LLaMA/OpenAI counts differ ~20%</td><td>MIT</td></tr></tbody></table><blockquote><p><strong>Practical shortcut:</strong> Most agents use <code>len(text) / 4</code> for quick estimates, then precise tokenization near context boundaries. Aider samples every 100th line and extrapolates — ~100× faster for large files.</p></blockquote><h3 id="code-intelligence-repo-mapping" tabindex="-1">Code Intelligence &amp; Repo Mapping <a class="header-anchor" href="#code-intelligence-repo-mapping" aria-label="Permalink to &quot;Code Intelligence &amp; Repo Mapping&quot;">​</a></h3><p>Understanding code structure — not just raw text — enables agents to select the <em>right</em> context.</p><ul><li><p><strong><a href="https://github.com/tree-sitter/tree-sitter" target="_blank" rel="noreferrer">tree-sitter</a></strong> — Incremental parsing library with 100+ language grammars. Builds concrete syntax trees that update on every keystroke, even with syntax errors. Powers repo maps, symbol extraction, and AST-aware chunking across Aider, GitHub Copilot, and Cursor. MIT.</p></li><li><p><strong><a href="https://github.com/Aider-AI/aider" target="_blank" rel="noreferrer">Aider repo-map</a></strong> — Three-step pipeline: (1) tree-sitter extracts symbol definitions and references, (2) builds a file-level dependency graph, (3) PageRank selects the most important symbols. Default budget is 1,024 tokens; expands to 8× when no files are in chat. Apache 2.0.</p></li><li><p><strong><a href="https://github.com/ast-grep/ast-grep" target="_blank" rel="noreferrer">ast-grep</a></strong> — Structural code search/replace built on tree-sitter. Uses pattern syntax (<code>$MATCH</code> wildcards) instead of regex, enabling precise code-pattern queries for context selection. MIT.</p></li><li><p><strong><a href="https://sourcegraph.com" target="_blank" rel="noreferrer">Sourcegraph / SCIP</a></strong> — Code intelligence platform using a layered approach: precise language-server indexers → tree-sitter heuristics → text search fallback. Demonstrates production-grade code understanding at scale.</p></li></ul><h3 id="memory-long-context-systems" tabindex="-1">Memory &amp; Long-Context Systems <a class="header-anchor" href="#memory-long-context-systems" aria-label="Permalink to &quot;Memory &amp; Long-Context Systems&quot;">​</a></h3><p>These projects give agents explicit control over what stays in context versus what gets paged out.</p><ul><li><p><strong><a href="https://github.com/letta-ai/letta" target="_blank" rel="noreferrer">Letta / MemGPT</a></strong> — Treats the context window like RAM in an OS. The agent manages its own memory via tools: <code>core_memory_append/replace</code> (always in-context), <code>archival_memory_insert/search</code> (vector-backed external storage), and <code>conversation_search</code> (recall). The most radical approach — the agent itself decides what to keep. Apache 2.0.</p></li><li><p><strong><a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">LangChain / LangGraph</a></strong> — Provides a menu of memory strategies: buffer, sliding window, summary, summary-buffer hybrid, token-budget, entity tracking, and vector-store retrieval. LangGraph adds checkpoint-based persistence with <code>SqliteSaver</code>/<code>PostgresSaver</code> and cross-thread memory via <code>Store</code>. MIT.</p></li><li><p><strong><a href="https://github.com/All-Hands-AI/OpenHands" target="_blank" rel="noreferrer">OpenHands condensers</a></strong> — Pluggable compaction system with ~10 strategies including LLM summarization, attention-based selection, amortized forgetting, hierarchical condensation, and observation masking. Demonstrates that no single strategy fits all situations. MIT.</p></li></ul><h3 id="code-rag-retrieval" tabindex="-1">Code RAG &amp; Retrieval <a class="header-anchor" href="#code-rag-retrieval" aria-label="Permalink to &quot;Code RAG &amp; Retrieval&quot;">​</a></h3><p>Retrieval-Augmented Generation for code requires code-aware chunking and multi-pass search.</p><ul><li><p><strong><a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">LlamaIndex</a></strong> — Data framework with a <code>CodeSplitter</code> that respects AST structure (whole functions, not random lines), hierarchical indices for broad-to-narrow search, and hybrid retrieval combining vectors with keywords. MIT.</p></li><li><p><strong><a href="https://github.com/voyage-ai/voyageai-python" target="_blank" rel="noreferrer">Voyage AI (<code>voyage-code-3</code>)</a></strong> — Code-specific embedding model trained on code + documentation pairs. Outperforms general-purpose embeddings (e.g., <code>text-embedding-3-small</code>) by 15-30% on code retrieval benchmarks. Includes reranker models.</p></li><li><p><strong><a href="https://github.com/chroma-core/chroma" target="_blank" rel="noreferrer">Chroma</a></strong> — Embeddable vector database with a 4-function API (create, add, query, get). Handles tokenization and embedding automatically; supports metadata filtering by file path, language, or function name. Apache 2.0.</p></li></ul><table tabindex="0"><thead><tr><th>Retrieval Approach</th><th>Speed</th><th>Semantic Accuracy</th><th>Best For</th></tr></thead><tbody><tr><td>Keyword / BM25</td><td>Fast</td><td>Low</td><td>Known identifiers, exact names</td></tr><tr><td>Embedding (general)</td><td>Medium</td><td>Medium</td><td>Natural-language queries</td></tr><tr><td>Embedding (code-specific)</td><td>Medium</td><td>High</td><td>Code search, cross-language</td></tr><tr><td>Hybrid (keyword + embedding)</td><td>Medium</td><td>High</td><td>Production systems</td></tr><tr><td>Multi-pass (lexical → embed → LLM rerank)</td><td>Slow</td><td>Highest</td><td>Complex retrieval tasks</td></tr></tbody></table><h3 id="codebase-search-understanding" tabindex="-1">Codebase Search &amp; Understanding <a class="header-anchor" href="#codebase-search-understanding" aria-label="Permalink to &quot;Codebase Search &amp; Understanding&quot;">​</a></h3><p>End-to-end platforms that index entire repositories for AI-powered code understanding.</p><ul><li><p><strong><a href="https://github.com/sweepai/sweep" target="_blank" rel="noreferrer">Sweep</a></strong> — Pioneered multi-pass retrieval for code: lexical search (fast) → embedding search (semantic) → LLM re-ranking. Uses AST-aware chunking and incremental indexing on git changes. BUSL-1.1.</p></li><li><p><strong><a href="https://greptile.com" target="_blank" rel="noreferrer">Greptile</a></strong> — Codebase understanding as a service. Indexes GitHub/GitLab repos; learns team coding standards from PR comments. Reports median time-to-merge drops from 20 hours to 1.8 hours. SOC 2 compliant; self-hosted option available.</p></li><li><p><strong><a href="https://docs.cursor.com/context/codebase-indexing" target="_blank" rel="noreferrer">Cursor codebase indexing</a></strong> — Embedding-based indexing with automatic re-indexing on file changes. Hybrid retrieval combines vector similarity with structural code understanding. <code>.cursorignore</code> for scoping. Arguably the most successful consumer-facing implementation.</p></li></ul><h3 id="persistence-memory-stores" tabindex="-1">Persistence &amp; Memory Stores <a class="header-anchor" href="#persistence-memory-stores" aria-label="Permalink to &quot;Persistence &amp; Memory Stores&quot;">​</a></h3><p>Long-lived agents need durable state across sessions, restarts, and crashes.</p><ul><li><p><strong>SQLite patterns</strong> — The dominant choice for single-agent persistence. OpenCode/Crush stores sessions and messages; Aider uses <code>diskcache</code> (SQLite-backed) for tag caching with mtime invalidation; LangGraph&#39;s <code>SqliteSaver</code> checkpoints entire agent state. Zero-config, single-file, ACID-compliant.</p></li><li><p><strong><a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">Mem0</a></strong> — Self-improving memory layer that automatically extracts facts from conversations, deduplicates, and resolves conflicts. Multi-level memory (user, session, agent) with vector + graph storage. Apache 2.0.</p></li><li><p><strong><a href="https://github.com/getzep/zep" target="_blank" rel="noreferrer">Zep</a></strong> — Long-term memory store with auto-summarization, named entity extraction, and temporal awareness. Native LangChain integration. Hybrid search (vector + metadata). Apache 2.0.</p></li></ul><table tabindex="0"><thead><tr><th>Memory Store</th><th>Auto-Extract</th><th>Summarization</th><th>Multi-Level</th><th>Search</th><th>Integration</th></tr></thead><tbody><tr><td>SQLite (raw)</td><td>No</td><td>Manual</td><td>No</td><td>SQL</td><td>Universal</td></tr><tr><td>Mem0</td><td>✅ Facts</td><td>✅</td><td>✅ User/session/agent</td><td>Vector + graph</td><td>REST API</td></tr><tr><td>Zep</td><td>✅ Entities</td><td>✅</td><td>Session-level</td><td>Vector + metadata</td><td>LangChain native</td></tr><tr><td>Letta/MemGPT</td><td>Agent-driven</td><td>Agent-driven</td><td>Core/archival/recall</td><td>Vector</td><td>Built-in tools</td></tr></tbody></table><hr><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Strategy</th><th>Reference</th></tr></thead><tbody><tr><td><strong>OpenHands</strong></td><td>10 condenser strategies, 6-layer context system</td><td><a href="./../agents/openhands/context-management.html"><code>../agents/openhands/context-management.md</code></a></td></tr><tr><td><strong>opencode</strong></td><td>Auto-compact with SQLite persistence</td><td><a href="./../agents/opencode/context-management.html"><code>../agents/opencode/context-management.md</code></a></td></tr><tr><td><strong>Claude Code</strong></td><td><code>/compact</code> command, CLAUDE.md, auto-memory</td><td><a href="./../agents/claude-code/context-management.html"><code>../agents/claude-code/context-management.md</code></a></td></tr><tr><td><strong>Goose</strong></td><td>3-level compaction, tool-pair summarization, MOIM</td><td><a href="./../agents/goose/context-management.html"><code>../agents/goose/context-management.md</code></a></td></tr><tr><td><strong>Codex</strong></td><td>Byte-based token estimation, auto-compaction</td><td><a href="./../agents/codex/context-management.html"><code>../agents/codex/context-management.md</code></a></td></tr><tr><td><strong>Gemini CLI</strong></td><td>1M token context utilization</td><td><a href="./../agents/gemini-cli/context-management.html"><code>../agents/gemini-cli/context-management.md</code></a></td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>Linear history — no compaction needed</td><td><a href="./../agents/mini-swe-agent/context-management.html"><code>../agents/mini-swe-agent/context-management.md</code></a></td></tr><tr><td><strong>Aider</strong></td><td>Repo-map (tree-sitter → graph → PageRank → token budget)</td><td><a href="./../agents/aider/context-management.html"><code>../agents/aider/context-management.md</code></a></td></tr><tr><td><strong>ForgeCode</strong></td><td>Bounded context across sub-agents, semantic entry-point discovery</td><td><a href="./../agents/forgecode/context-management.html"><code>../agents/forgecode/context-management.md</code></a></td></tr></tbody></table>`,159)])])}const g=t(o,[["render",r]]);export{m as __pageData,g as default};
